"""Hermes Workspace Proxy with WebSocket support."""
import http.server
import urllib.request
import socketserver
import socket
import select
import threading

TARGET = ("127.0.0.1", 8789)
CATCH_ROUTES = {"/api/gateway/sessions", "/api/cli-agents"}

class ProxyHandler(http.server.BaseHTTPRequestHandler):
    def do_GET(self):
        self._handle("GET")
    def do_POST(self):
        self._handle("POST")
    def do_PUT(self):
        self._handle("PUT")
    def do_DELETE(self):
        self._handle("DELETE")
    def do_PATCH(self):
        self._handle("PATCH")
    def do_HEAD(self):
        self._handle("HEAD")

    def _handle(self, method):
        path = self.path.split("?")[0]
        for pfx in CATCH_ROUTES:
            if path == pfx or path.startswith(pfx + "/"):
                self.send_response(404)
                self.end_headers()
                self.wfile.write(b'{"ok":false,"error":"Blocked by proxy"}')
                return

        # Check for WebSocket upgrade
        upgrade = self.headers.get("Upgrade", "").lower()
        if upgrade == "websocket":
            return self._handle_websocket()

        # Standard HTTP forward
        cl = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(cl) if cl else None
        try:
            req = urllib.request.Request(
                f"http://{TARGET[0]}:{TARGET[1]}{self.path}",
                data=body,
                headers=dict(self.headers),
                method=method
            )
            with urllib.request.urlopen(req, timeout=30) as resp:
                self.send_response(resp.status)
                for k, v in resp.headers.items():
                    if k.lower() not in ("transfer-encoding", "content-encoding", "content-length"):
                        self.send_header(k, v)
                if resp.headers.get("Content-Length"):
                    self.send_header("Content-Length", resp.headers["Content-Length"])
                self.end_headers()
                while True:
                    chunk = resp.read(65536)
                    if not chunk:
                        break
                    self.wfile.write(chunk)
                    self.wfile.flush()
        except urllib.error.HTTPError as e:
            self.send_response(e.code)
            for k, v in e.headers.items():
                if k.lower() not in ("transfer-encoding", "content-encoding"):
                    self.send_header(k, v)
            self.end_headers()
            self.wfile.write(e.read())
        except Exception as e:
            self.send_response(502)
            self.end_headers()
            self.wfile.write(f'{{"error":"Proxy error: {str(e)}"}}'.encode())

    def _handle_websocket(self):
        """Bidirectional TCP tunnel for WebSocket upgrade requests."""
        try:
            # Connect to target
            remote = socket.create_connection(TARGET, timeout=10)
            # Send the raw HTTP request to upgrade
            raw_req = f"{self.command} {self.path} HTTP/1.1\r\n"
            for k, v in self.headers.items():
                raw_req += f"{k}: {v}\r\n"
            raw_req += "\r\n"
            remote.sendall(raw_req.encode())

            # Read upgrade response
            response = b""
            while b"\r\n\r\n" not in response:
                chunk = remote.recv(4096)
                if not chunk:
                    break
                response += chunk

            # Forward status line + headers to client
            header_end = response.index(b"\r\n\r\n") + 4
            status_line = response[:response.index(b"\r\n")]
            parts = status_line.split(b" ", 2)
            code = int(parts[1]) if len(parts) > 1 else 502

            # Parse and forward headers
            head_data = response[:header_end]
            self.send_response(code)
            for line in head_data.split(b"\r\n")[1:-2]:
                if b":" in line:
                    k, v = line.split(b":", 1)
                    k = k.decode().strip().lower()
                    if k not in ("transfer-encoding", "content-encoding", "content-length"):
                        self.send_header(k.strip(), v.strip().decode())
            self.end_headers()

            # Bidirectional copy (WebSocket frames)
            self.connection.setblocking(0)
            remote.setblocking(0)
            try:
                while True:
                    r, _, _ = select.select([self.connection, remote], [], [], 30)
                    if self.connection in r:
                        data = self.connection.recv(65536)
                        if not data:
                            break
                        remote.sendall(data)
                    if remote in r:
                        data = remote.recv(65536)
                        if not data:
                            break
                        self.connection.sendall(data)
            except (BrokenPipeError, ConnectionResetError, OSError):
                pass
            finally:
                remote.close()
        except Exception as e:
            try:
                self.send_response(502)
                self.end_headers()
                self.wfile.write(f'{{"error":"WebSocket proxy error: {str(e)}"}}'.encode())
            except:
                pass

    def log_message(self, fmt, *args):
        print(f"[proxy] {args[0]} {args[1]} {args[2]}")

def run(host="0.0.0.0", port=8788):
    server = socketserver.ThreadingTCPServer((host, port), ProxyHandler, bind_and_activate=False)
    server.socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server.server_bind()
    server.server_activate()
    print(f"[proxy] Threaded server on {host}:{port} -> http://{TARGET[0]}:{TARGET[1]}")
    server.serve_forever()

if __name__ == "__main__":
    run()", "exit_code": 0, "error": null}

